scwin.f_Retrieve = async function () {
  let chk = await $c.gus.cfValidate($p, [ed_bilgLodeptCd, ica_qryConDtFm, ica_qryConDtTo]);
  if (!chk) {
    return;
  }
  if (!$c.gus.cfIsAfterDate($p, ica_qryConDtFm.getValue(), ica_qryConDtTo.getValue())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    return;
  }
  dma_selldecunsetaggr_con.set("coCd", ed_coCd.getValue());
  dma_selldecunsetaggr_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());
  dma_selldecunsetaggr_con.set("bilgClntNo", ed_bilgClntNo.getValue());
  dma_selldecunsetaggr_con.set("qryConDtFm", ica_qryConDtFm.getValue());
  dma_selldecunsetaggr_con.set("qryConDtTo", ica_qryConDtTo.getValue());
  dma_selldecunsetaggr_con.set("regId", ed_regId.getValue());
  dma_selldecunsetaggr_con.set("modId", ed_modId.getValue());
  dma_selldecunsetaggr_con.set("gubun", lc_gubun.getValue());
  dma_selldecunsetaggr_con.set("aggbilgClntNo", ed_bilgClntNo.getValue());
  dma_selldecunsetaggr_con.set("aggsellItemCd", "");
  dma_selldecunsetaggr_con.set("aggtaxnClsCd", "");
  ds_selldecunsetdetail.removeAll();
  spa_totalRow2.setValue(0);
  if (acb_qryConKnd.getValue() == "오더") {
    scwin.qryConKnd = "오더일자";
  } else if (acb_qryConKnd.getValue() == "실적") {
    scwin.qryConKnd = "실적일자";
  } else if (acb_qryConKnd.getValue() == "회계") {
    scwin.qryConKnd = "회계일자";
  } else if (acb_qryConKnd.getValue() == "오더번호") {
    scwin.qryConKnd = "오더번호";
  }
  dma_selldecunsetaggr_con.set("qryConKnd", acb_qryConKnd.getValue());
  dma_selldecunsetaggr_con.set("qryConCd", ed_qryConCd.getValue());
  await $c.sbm.execute($p, sbm_selldecunsetaggr_retrieve);
  let detailAllChecked = false;
  try {
    detailAllChecked = chb_detailAllYn.getValue() != "";
  } catch (e) {
    detailAllChecked = false;
  }
  if (detailAllChecked) {
    scwin.f_SellingDecDetailRetrieve();
  }
};
