scwin.f_changeSellInfoWhole = async function () {
  let stPos = ds_selldecunsetdetail.getRowPosition();
  let lcBilgClntNo = ds_selldecunsetdetail.getCellData(stPos, "bilgClntNo");
  let lcBilgClntNm = ds_selldecunsetdetail.getCellData(stPos, "bilgClntNm");
  let lcTaxnClsCd = ds_selldecunsetdetail.getCellData(stPos, "taxnClsCd");
  let lcTsVsslCd = ds_selldecunsetdetail.getCellData(stPos, "tsVsslCd");
  let lcTsPortcnt = ds_selldecunsetdetail.getCellData(stPos, "tsPortcnt");
  let lcBilgIntendDt = ds_selldecunsetdetail.getCellData(stPos, "bilgIntendDt");
  let lcBilgLodeptCd = ds_selldecunsetdetail.getCellData(stPos, "bilgLodeptCd");
  let focusedCol = gr_selldecunsetdetail.getFocusedColumnID ? gr_selldecunsetdetail.getFocusedColumnID() : "";
  for (let i = stPos; i < ds_selldecunsetdetail.getRowCount(); i++) {
    if (ds_selldecunsetdetail.getCellData(i, "dcsnClsCd") != "1") {
      await $c.gus.cfAlertMsg($p, "미확인 내역만 수정이 가능합니다.", []);
      return false;
    }
    if (ds_selldecunsetdetail.getCellData(i, "dcsnClsCd") == "1") {
      ds_selldecunsetdetail.setCellData(i, "chk", "T");
    }
    if (focusedCol == "bilgClntNo" || focusedCol == "bilgClntNm") {
      ds_selldecunsetdetail.setCellData(i, "bilgClntNo", lcBilgClntNo);
      ds_selldecunsetdetail.setCellData(i, "bilgClntNm", lcBilgClntNm);
    }
    if (focusedCol == "taxnClsCd") {
      ds_selldecunsetdetail.setCellData(i, "taxnClsCd", lcTaxnClsCd);
      if (ds_selldecunsetdetail.getCellData(i, "taxnClsCd") == "01") {
        ds_selldecunsetdetail.setCellData(i, "vatAmt", Math.round(ds_selldecunsetdetail.getCellData(i, "sellAmt") * 0.1));
      } else {
        ds_selldecunsetdetail.setCellData(i, "vatAmt", 0);
      }
    }
    if (focusedCol == "vsslCd" || focusedCol == "tsVsslCd" || focusedCol == "tsPortcnt") {
      ds_selldecunsetdetail.setCellData(i, "tsVsslCd", lcTsVsslCd);
      ds_selldecunsetdetail.setCellData(i, "tsPortcnt", lcTsPortcnt);
    }
    if (focusedCol == "bilgIntendDt") {
      ds_selldecunsetdetail.setCellData(i, "bilgIntendDt", lcBilgIntendDt);
    }
    if (focusedCol == "bilgLodeptCd") {
      ds_selldecunsetdetail.setCellData(i, "bilgLodeptCd", lcBilgLodeptCd);
    }
  }
  return true;
};
scwin.f_validateSellInfo = async function () {
  for (let i = 0; i < ds_selldecunsetdetail.getRowCount(); i++) {
    let rowStatus = ds_selldecunsetdetail.getRowStatus(i);
    if (rowStatus != "U") {
      continue;
    }
    if (ds_selldecunsetdetail.getCellData(i, "dcsnClsCd") != "1") {
      await $c.gus.cfAlertMsg($p, "미확인 내역만 수정이 가능합니다.", []);
      return false;
    }
    if ($c.gus.cfIsNull($p, ds_selldecunsetdetail.getCellData(i, "bilgClntNo"))) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["청구거래처 "]);
      return false;
    }
    if ($c.gus.cfIsNull($p, ds_selldecunsetdetail.getCellData(i, "bilgLodeptCd"))) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["청구부서 "]);
      return false;
    }
    if ($c.gus.cfIsNull($p, ds_selldecunsetdetail.getCellData(i, "taxnClsCd"))) {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["과세 "]);
      return false;
    }
    if (ds_selldecunsetdetail.getCellData(i, "taxnClsCd") == "01") {
      ds_selldecunsetdetail.setCellData(i, "vatAmt", Math.round(ds_selldecunsetdetail.getCellData(i, "sellAmt") * 0.1));
    } else {
      ds_selldecunsetdetail.setCellData(i, "vatAmt", 0);
    }
  }
  return true;
};
