scwin.gr_selldecunsetdetail_oncloseup = function (rowIndex, columnIndex, columnId) {
  let rowPos = ds_selldecunsetdetail.getRowPosition();
  let sellGoodsPatternCd = ds_selldecunsetdetail.getCellData(rowPos, "sellGoodsPatternCd");
  if (columnId == "sellGoodsPatternCd") {
    if (sellGoodsPatternCd == "02") {
      ds_selldecunsetdetail.setCellData(rowPos, "sellCommNo", "");
      // TODO: f_openPopUpCommInfo 품명팝업
    } else if (sellGoodsPatternCd == "03") {
      // TODO: f_openPopUpKndVehcl 장비팝업
    } else {
      ds_selldecunsetdetail.setCellData(rowPos, "sellCommNo", "");
      ds_selldecunsetdetail.setCellData(rowPos, "sellCommNm", "");
    }
  } else if (columnId == "sellUnitCd") {
    for (let i = 0; i < ds_unitCd.getRowCount(); i++) {
      if (ds_selldecunsetdetail.getCellData(rowPos, "sellUnitCd") == ds_unitCd.getCellData(i, "cd")) {
        ds_selldecunsetdetail.setCellData(rowPos, "unitClsCd", ds_unitCd.getCellData(i, "upperCd"));
        break;
      }
    }
    // TODO: f_AmtSet(ds_selldecunsetdetail, rowIndex, "sellAmt", "SELL");
  } else if (columnId == "taxnClsCd") {
    if (ds_selldecunsetdetail.getCellData(rowPos, "taxnClsCd") == "01") {
      ds_selldecunsetdetail.setCellData(rowPos, "vatAmt", Math.round(ds_selldecunsetdetail.getCellData(rowPos, "sellAmt") * 0.1));
    } else {
      ds_selldecunsetdetail.setCellData(rowPos, "vatAmt", 0);
    }
  }
};
